//背包+容斥
#include <bits/stdc++.h>
using namespace std;

int c[4],t,d[4],s;
long long f[100005];

int main(){
    scanf("%d%d%d%d%d",&c[0],&c[1],&c[2],&c[3],&t);
    f[0]=1;
    for(int i=0;i<4;i++)
    	for(int j=c[i];j<=1e5;j++)
    		f[j]+=f[j-c[i]];
    while(t--){
        long long ans=0;
        scanf("%d%d%d%d%d",&d[0],&d[1],&d[2],&d[3],&s);
        for(int i=0;i<16;i++){
            long long sum=0;
            int cnt=0,tmp=i;
            while(tmp){
                int num=(int)log2(tmp&(-tmp));
                cnt++,sum+=1LL*(d[num]+1)*c[num];
                tmp-=(tmp&(-tmp));
            }
            if(sum>s)
                continue;
            if(cnt%2)
                ans-=f[s-sum];
            else
                ans+=f[s-sum];
        }
        printf("%lld\n",ans);
    }
}
